//! Canonical auxiliary generation for alpha-collapsed inductive blocks.
//!
//! When `sort_consts` collapses N mutual inductives into fewer equivalence
//! classes, Lean's auto-generated auxiliaries that reference `.rec` directly
//! (`.rec` itself, `.recOn`, `.casesOn`, `.below`, `.brecOn`) have the wrong
//! arity — they were built against the pre-collapse motive/minor layout.
//! Rather than surgically patching them (fragile, source-order dependent),
//! we regenerate them from the canonical class structure.
//!
//! Only generates an auxiliary if the original Lean constant exists in the
//! environment — correctly handles bootstrap-early types (e.g., Eq has no .below).
//!
//! # Which auxiliaries need regeneration, and which do not
//!
//! The critical question for each Lean-generated auxiliary is: **does its
//! value reference `.rec` directly?** Only `.rec` changes arity under alpha
//! collapse (fewer motives, fewer minors, merged classes). Every other
//! auxiliary Lean generates is either derived from `.rec` (needs regen) or
//! derived from `.casesOn` (does not).
//!
//! `.casesOn`'s **public** binder arity is invariant under alpha collapse:
//! it always binds exactly
//!
//! ```text
//!   params + 1 target-motive + indices + 1 major + (target ctor count) minors
//! ```
//!
//! regardless of how many sibling inductives collapse with the target. Only
//! its *internal* body changes — it now calls a collapsed `.rec` with fewer
//! motive/minor slots. So any auxiliary whose value only invokes `.casesOn`
//! (never `.rec`) type-checks unmodified against our regenerated `.casesOn`.
//!
//! ## Regenerated here (reference `.rec` directly)
//!
//! | Auxiliary        | Built in             |
//! |------------------|----------------------|
//! | `.rec`           | `recursor.rs`        |
//! | `.recOn`         | `rec_on.rs`          |
//! | `.casesOn`       | `cases_on.rs`        |
//! | `.below` (Type)  | `below.rs` `BelowDef`|
//! | `.below` (Prop)  | `below.rs` `BelowIndc` (inductive; its own `.rec`) |
//! | `.brecOn`        | `brecon.rs`          |
//! | `.brecOn.go`     | `brecon.rs`          |
//! | `.brecOn.eq`     | `brecon.rs`          |
//!
//! Plus the nested-inductive variants `.rec_N`, `.below_N`, `.brecOn_N[.go|.eq]`
//! generated for auxiliary members of the expanded flat block.
//!
//! ## Implicitly covered (reference only `.casesOn`, so inherit correctness)
//!
//! These are **not** regenerated — they compile directly from the original
//! Lean environment, and their `.casesOn` references bind to the regenerated
//! auxiliary at address-resolution time. No patching is needed.
//!
//! - `.noConfusion`, `.noConfusionType`
//! - `.ctor.noConfusion` (per-constructor specialization)
//! - `.ctor.inj`, `.ctor.injEq` (derived from `.noConfusion`)
//! - `.ctorIdx`, `.toCtorIdx`
//! - `.ctorElim`, `.ctorElimType`, `.ctor.elim`
//! - `._sizeOf_*`, `.ctor.sizeOf_spec` (independent of `.rec`)
//!
//! Empirical confirmation: the `validate-aux` test roundtrips all of these
//! across alpha-collapsed multi-ctor blocks (e.g., `TreeA/TreeB`, `FA/FB`,
//! `RoseA/RoseB`) with zero mismatches over 25k+ constants.
//!
//! ## Not automatically generated by Lean for every inductive
//!
//! These are produced on demand by specific tactics or user request rather
//! than by `addDecl`, so they don't appear in every compiled environment
//! and require no handling here unless a downstream user explicitly depends
//! on one (at which point the same "only references `.casesOn`" analysis
//! applies to them as well):
//!
//! - `.sparseCasesOn`, `.sparseCasesOnEq`
//! - `.casesOnSameCtor`, `.casesOnSameCtorHet`

pub(crate) mod below;
pub(crate) mod brecon;
pub(crate) mod cases_on;
pub(crate) mod expr_utils;
pub(crate) mod nested;
pub(crate) mod rec_on;
pub(crate) mod recursor;

use std::sync::Arc;

use rustc_hash::FxHashMap;

use crate::ix::compile::CompileState;
use crate::ix::env::{
  ConstantVal, Env as LeanEnv, Expr as LeanExpr, Name, RecursorRule,
  RecursorVal,
};
use crate::ix::ixon::CompileError;

/// A regenerated constant ready for compilation.
#[derive(Clone)]
pub(crate) enum PatchedConstant {
  /// A regenerated `.rec` recursor.
  Rec(RecursorVal),
  /// A regenerated `.recOn` definition (arg-reordered `.rec` wrapper).
  RecOn(AuxDef),
  /// A regenerated `.casesOn` definition (`.rec` wrapper without inductive hypotheses).
  CasesOn(AuxDef),
  /// A regenerated `.below` definition (Type-level case).
  BelowDef(below::BelowDef),
  /// A regenerated `.below` inductive (Prop-level case).
  BelowIndc(below::BelowIndc),
  /// A regenerated `.brecOn` (or `.brecOn.go`, `.brecOn.eq`) definition.
  BRecOn(brecon::BRecOnDef),
}

/// A simple auxiliary definition (type + value + level params).
///
/// `is_unsafe` mirrors the parent inductive's `is_unsafe` flag so downstream
/// emission can pick the correct `DefinitionSafety`. Lean's
/// `mkDefinitionValInferringUnsafe` (`refs/lean4/src/Lean/Environment.lean:2790`)
/// flips to `Unsafe` whenever the type or value mentions any unsafe constant —
/// and every auxiliary references its parent inductive.
#[derive(Clone)]
pub(crate) struct AuxDef {
  pub name: Name,
  pub level_params: Vec<Name>,
  pub typ: LeanExpr,
  pub value: LeanExpr,
  pub is_unsafe: bool,
}

/// Output of [`generate_aux_patches`].
///
/// In addition to the patch map, carries the canonical hash-sort permutation
/// so callers can reuse it — both during compile (to build the
/// `CallSitePlan` / surgery layout) and during decompile / validation
/// (to canonicalize Lean-source-order originals before structural
/// comparison).
#[derive(Clone, Default)]
pub(crate) struct AuxPatchesOutput {
  /// The regenerated canonical-layout constants, keyed by their
  /// Lean-visible source-indexed name (e.g. `A.rec`, `A.below_2`).
  pub patches: FxHashMap<Name, PatchedConstant>,
  /// Lean-visible aux names that should resolve to an already-compiled
  /// canonical patch instead of compiling their own renamed copy.
  ///
  /// Key is the source name exported by Lean; value is the generated patch
  /// name whose address should be reused. These are aliases, not new
  /// constants.
  pub aliases: FxHashMap<Name, Name>,
  /// Hash-sort permutation for the aux section of the expanded block:
  /// `perm[source_j] = canonical_i` for each source-walk aux position.
  /// `None` when the block has no nested auxiliaries (or the aux_gen
  /// pipeline didn't reach the hash-sort step, e.g. empty `original_all`).
  pub perm: Option<Vec<usize>>,
  /// Number of equivalence classes — i.e. primary (non-aux) members in the
  /// canonical block. Reserved for callers that need to build
  /// [`congruence::perm::PermCtx`] (see the `validate-aux` Phase 2 path in
  /// `ffi/lean_env.rs`); the Phase 2 builder currently derives this from
  /// the `all` slice directly, but keep the field exposed so future
  /// callers don't have to duplicate the singleton-classes assumption.
  #[allow(dead_code)]
  pub n_classes: usize,
  /// Number of canonical aux members (== length of the hash-sorted aux
  /// section). Zero for blocks without nested inductives. Reserved for
  /// downstream diagnostics / metadata; not read by the current
  /// pipeline.
  #[allow(dead_code)]
  pub n_canonical_aux: usize,
  /// Number of source-walk aux positions (== `perm.len()` when `perm` is
  /// `Some`). Under alpha collapse this can exceed `n_canonical_aux`.
  /// Reserved for diagnostics — same rationale as `n_canonical_aux`.
  #[allow(dead_code)]
  pub n_source_aux: usize,
}

/// Generate all canonical auxiliary patches for a collapsed inductive block.
///
/// Called from `compile_mutual` after `sort_consts` determines the canonical
/// classes. Returns an [`AuxPatchesOutput`] carrying the patch map and the
/// canonical hash-sort permutation (when applicable).
///
/// Only generates patches when alpha-collapse or SCC-splitting actually
/// changes the block structure. Each auxiliary is only generated if the
/// original Lean constant exists in the environment.
///
/// `original_all` is the Lean-source-walk inductive name list (typically
/// `InductiveVal.all` of any block member). It determines the canonical
/// `<all0>.rec_N` naming and the source-aux walk used to compute the
/// hash-sort permutation.
pub(crate) fn generate_aux_patches(
  sorted_classes: &[Vec<Name>],
  original_all: &[Name],
  lean_env: &Arc<LeanEnv>,
  stt: &CompileState,
  kctx: &crate::ix::compile::KernelCtx,
) -> Result<AuxPatchesOutput, CompileError> {
  let mut patches: FxHashMap<Name, PatchedConstant> = FxHashMap::default();
  let mut aliases: FxHashMap<Name, Name> = FxHashMap::default();

  if original_all.is_empty() {
    return Ok(AuxPatchesOutput {
      patches,
      aliases,
      perm: None,
      n_classes: sorted_classes.len(),
      n_canonical_aux: 0,
      n_source_aux: 0,
    });
  }

  let n_classes = sorted_classes.len();

  // Captured below when we take the expand/restore path. Returned to the
  // caller so Phase 2 / Phase 6 / Phase 7b can permute Lean-source-order
  // originals into canonical order before structural comparison.
  let mut captured_perm: Option<Vec<usize>> = None;
  let mut captured_n_canonical_aux: usize = 0;
  let mut captured_n_source_aux: usize = 0;

  // NOTE: the historical `perm_rename_map` (canonical→source `_N`
  // rename, applied post-generation over `.below`/`.brecOn*` patch
  // bodies) has been eliminated. Generators now emit source-indexed
  // `_N` suffixes directly via the `source_of_canonical` slice threaded
  // through `generate_recursors_from_expanded`. See
  // `docs/ix_canonicity.md` §6.4 on the two numberings.

  // Ensure PUnit and PProd are in kenv BEFORE any ingress (Phase 1) runs.
  // ingress_field_deps may encounter PProd in constructor field types and
  // would insert it as a bare Axio stub; the hardcoded Indc definitions
  // here are authoritative and must be present first.
  expr_utils::ensure_prelude_in_kenv_of(stt, kctx);

  // Phase 1: Generate canonical recursors.
  //
  // For blocks with nested inductive occurrences, use the expand/restore
  // model: replace nested refs (like `Array (Part α)`) with auxiliary
  // consts (`_nested.Array_1 α`), build recursors uniformly, then restore
  // the aux refs back to original nested expressions.
  let _p1_start = std::time::Instant::now();
  // Build the ordered list of class representatives (one per class).
  // This is the "canonical mutual block" that we treat as a valid Lean
  // declaration and expand nested occurrences from.
  let ordered_originals: Vec<Name> =
    sorted_classes.iter().map(|c| c[0].clone()).collect();
  // Lean's `num_nested` metadata is not a complete structural detector for
  // all exported forms (notably some parameterized nested blocks). Probe our
  // own expansion result instead, so aux aliases are generated whenever the
  // recursor generator will see flat auxiliaries.
  let alias_to_rep: FxHashMap<Name, Name> = sorted_classes
    .iter()
    .flat_map(|class| {
      class[1..].iter().map(move |alias| (alias.clone(), class[0].clone()))
    })
    .collect();
  let expanded_probe =
    nested::expand_nested_block(&ordered_originals, lean_env, &alias_to_rep)?;
  let structural_has_nested =
    expanded_probe.types.len() > expanded_probe.n_originals;
  let metadata_has_nested = original_all.iter().any(|name| {
    matches!(
      lean_env.get(name),
      Some(crate::ix::env::ConstantInfo::InductInfo(v))
        if crate::ix::compile::nat_conv::nat_to_usize(&v.num_nested) > 0
    )
  });
  let (canonical_recs, is_prop) = if metadata_has_nested
    && structural_has_nested
  {
    let mut expanded = expanded_probe;
    // Canonicalize the aux section of the expanded block by structural order.
    // After this, patches (recs, belows, brecOns, etc.) are emitted in
    // canonical order rather than Lean's source-walk order.
    //
    // Why this must happen here: call-site surgery uses `aux_perms` to
    // reorder user code's arguments when they call the aux. If the patch
    // layout doesn't match what surgery thinks it is, downstream bodies
    // that reference the aux (notably `_sizeOf_*`) wind up with mismatched
    // addresses. Keeping a single canonical layout shared by compile,
    // decompile, and surgery is the only way to maintain that the same
    // semantic block declared in permuted source orders hashes to the
    // same Ixon bytes.
    nested::sort_aux_by_partition_refinement(&mut expanded, stt)?;
    if expanded.types.len() > expanded.n_originals {
      // Compute source→canonical permutation FIRST (before recursor
      // generation) so the generator can emit source-indexed `_N`
      // suffixes directly, avoiding any canonical-then-rename
      // intermediate state. Lean exports `<all0>.rec_{source_j+1}`,
      // `.below_{source_j+1}`, `.brecOn_{source_j+1}`; our canonical
      // structural sort places the same auxes at different positions.
      // `perm[source_j] = canonical_i` captures the mapping, and
      // `source_of_canonical[canonical_i] = min source_j` is its
      // semantic inverse (modulo alpha-collapse dedup, which makes the
      // forward perm non-injective).
      let orig_to_canon_map: std::collections::HashMap<Name, Name> =
        sorted_classes
          .iter()
          .flat_map(|class| {
            let rep = class[0].clone();
            class.iter().map(move |n| (n.clone(), rep.clone()))
          })
          .collect();
      let n_canon = expanded.types.len().saturating_sub(expanded.n_originals);
      let perm = nested::compute_aux_perm(
        &expanded,
        original_all,
        lean_env,
        stt,
        &orig_to_canon_map,
      )?;
      // Stash for caller (Phase 2 / Phase 6 / Phase 7b need it).
      captured_perm = Some(perm.clone());
      captured_n_canonical_aux = n_canon;
      captured_n_source_aux = perm.len();

      // `canon_repr[canonical_i]` = min source_j mapping to this
      // canonical aux. Under alpha-collapse (n_source > n_canon)
      // multiple source names map to the same canonical; the min
      // ensures determinism. For well-formed in-SCC blocks every
      // canonical slot has at least one source mapping.
      let mut canon_repr = vec![usize::MAX; n_canon];
      for (src_j, &canon_i) in perm.iter().enumerate() {
        if canon_i != nested::PERM_OUT_OF_SCC
          && canon_i < n_canon
          && canon_repr[canon_i] == usize::MAX
        {
          canon_repr[canon_i] = src_j;
        }
      }

      // Sanity: every canonical aux must correspond to a real Lean-exported
      // source aux name. Synthesizing `<all0>.rec_{canonical_i+1}` /
      // `.below_{canonical_i+1}` / `.brecOn_{canonical_i+1}` would create
      // public names that Lean never exported, and later aliasing would make
      // those names look canonical. Treat that as a construction bug instead.
      for (ci, &source_j) in canon_repr.iter().enumerate() {
        if source_j == usize::MAX {
          return Err(CompileError::InvalidMutualBlock {
            reason: format!(
              "aux_gen canonical aux #{ci} has no Lean source mapping; refusing to synthesize canonical-indexed _N names",
            ),
          });
        }
      }
      let source_of_canonical: Vec<usize> = canon_repr.clone();

      // Has auxiliaries — use expand/restore path.
      // Pass source_of_canonical so the generator emits aux rec names
      // with Lean-source-indexed `_N` suffixes directly.
      let (raw_recs, is_prop) = recursor::generate_recursors_from_expanded(
        sorted_classes,
        &expanded,
        Some(&source_of_canonical),
        lean_env,
        stt,
        kctx,
      )?;

      // Build `aux_rec_map` for `RestoreCtx`: maps each `_nested.X.rec`
      // (the aux inductive's own derived recursor, as it appears in raw
      // rec bodies before restoration) to the Lean-source-indexed name
      // `<source_all0>.rec_{source_j+1}`. `source_j = canon_repr[canonical_i]`
      // is the min source index mapping to this canonical aux.
      //
      // Historical context: earlier versions of this loop also inserted
      // blanket `_N`-suffix rename entries for `.rec_{canonical+1}`,
      // `.below_{canonical+1}`, and `.brecOn_{canonical+1}.*` keys,
      // plus a separate `perm_rename_map` post-pass over `.below` /
      // `.brecOn*` patch bodies, because the generators emitted
      // canonical-indexed references internally. Since recursor.rs now
      // threads `source_of_canonical` into name construction, all those
      // entries would be no-ops — and `below.rs` / `brecon.rs` read
      // their `_N` suffixes from the already-renamed aux rec names, so
      // their bodies land in source indexing directly. Only the
      // `_nested.X.rec` mapping remains necessary; see
      // `docs/ix_canonicity.md` §6.4.
      //
      // `original_all[0]` is the Lean-source-order first inductive —
      // what Lean hangs `_N` names off in its env, and what
      // `below::generate_below_constants` / `brecon::generate_brecon_constants`
      // read from `first_ind.all[0]` for their own `_N` naming.
      // Using `ordered_originals[0]` (a class rep) would diverge
      // whenever sort_consts reorders the first class.
      let mut aux_rec_map: FxHashMap<Name, Name> = FxHashMap::default();
      let source_all0 = &original_all[0];
      for (canonical_i, member) in
        expanded.types.iter().skip(expanded.n_originals).enumerate()
      {
        let source_j = source_of_canonical[canonical_i];

        let aux_nested_rec_name =
          Name::str(member.name.clone(), "rec".to_string());
        let source_rec_name =
          Name::str(source_all0.clone(), format!("rec_{}", source_j + 1));
        aux_rec_map.insert(aux_nested_rec_name, source_rec_name);
      }

      let restore_ctx = expr_utils::RestoreCtx::new(
        expanded.aux_to_nested,
        expanded.aux_ctor_map,
        aux_rec_map,
        expanded.block_param_fvars,
        expanded.types.first().map_or(0, |t| t.n_params),
      );

      // Rename and restore all recursors.
      // Auxiliary recursors (_nested.X.rec) → canonical names (all[0].rec_N).
      // Constructor names in rules also need renaming.
      let original_all: Vec<Name> = expanded.types[..expanded.n_originals]
        .iter()
        .map(|t| t.name.clone())
        .collect();

      let restored_recs: Vec<(Name, RecursorVal)> = raw_recs
        .into_iter()
        .map(|(name, rv)| {
          // Rename the recursor name itself.
          let new_name =
            restore_ctx.aux_rec_map.get(&name).cloned().unwrap_or(name);

          // Restore type expression.
          let restored_type = restore_ctx.restore(&rv.cnst.typ);

          // Restore rule RHS and rename constructor names.
          let restored_rules: Vec<RecursorRule> = rv
            .rules
            .iter()
            .map(|r| {
              let new_ctor = restore_ctx
                .aux_ctor_map
                .get(&r.ctor)
                .map_or_else(|| r.ctor.clone(), |(orig_ctor, _)| orig_ctor.clone());
              RecursorRule {
                ctor: new_ctor,
                n_fields: r.n_fields.clone(),
                rhs: restore_ctx.restore(&r.rhs),
              }
            })
            .collect();

          (
            new_name.clone(),
            RecursorVal {
              cnst: ConstantVal {
                name: new_name,
                typ: restored_type,
                level_params: rv.cnst.level_params,
              },
              all: original_all.clone(),
              rules: restored_rules,
              ..rv
            },
          )
        })
        .collect();
      (restored_recs, is_prop)
    } else {
      // The structural detector can find auxiliaries in cases where Lean's
      // `num_nested` metadata is zero (notably parameterized nested blocks).
      // In those cases the standard flat-block recursor generator matches
      // Lean's original telescope, but we still need the source→canonical
      // permutation so extra Lean aux names can become address aliases instead
      // of falling back to original compilation.
      if structural_has_nested {
        let expanded_for_perm = nested::expand_nested_block(
          &ordered_originals,
          lean_env,
          &alias_to_rep,
        )?;
        let orig_to_canon_map: std::collections::HashMap<Name, Name> =
          sorted_classes
            .iter()
            .flat_map(|class| {
              let rep = class[0].clone();
              class.iter().map(move |n| (n.clone(), rep.clone()))
            })
            .collect();
        let n_canon = expanded_for_perm
          .types
          .len()
          .saturating_sub(expanded_for_perm.n_originals);
        let perm = nested::compute_aux_perm(
          &expanded_for_perm,
          original_all,
          lean_env,
          stt,
          &orig_to_canon_map,
        )?;
        captured_perm = Some(perm.clone());
        captured_n_canonical_aux = n_canon;
        captured_n_source_aux = perm.len();
      }
      // No expand/restore recursor generation — fall through to standard path.
      recursor::generate_canonical_recursors_with_overlay(
        sorted_classes,
        lean_env,
        None,
        None,
        stt,
        kctx,
      )?
    }
  } else {
    // No nested types at all — standard path.
    recursor::generate_canonical_recursors_with_overlay(
      sorted_classes,
      lean_env,
      None,
      None,
      stt,
      kctx,
    )?
  };
  let _p1_elapsed = _p1_start.elapsed();

  for (rec_name, rec_val) in &canonical_recs {
    // Only emit .rec if the original Lean env has it (some inductives,
    // e.g. structures, may not have .rec in the exported env subset).
    if lean_env.get(rec_name).is_some() {
      patches.insert(rec_name.clone(), PatchedConstant::Rec(rec_val.clone()));
    }
  }

  // Phase 1b: Generate .casesOn definitions.
  // .casesOn is a definition that wraps .rec, stripping IH fields from minors
  // and replacing non-target motives with PUnit. Needed by .brecOn.eq which
  // uses casesOn-based proofs (via Lean's `cases` tactic).
  //
  // Only generate for original recursors (first n_classes), not auxiliary rec_N.
  // This is intentional: Lean does NOT generate casesOn_N for nested auxiliary
  // types (unlike below_N/brecOn_N which ARE generated via BRecOn.lean).
  for (rec_name, rec_val) in canonical_recs.iter().take(n_classes) {
    // Build casesOn name: rec_name is "I.rec", casesOn name is "I.casesOn"
    let ind_name = match rec_name.as_data() {
      crate::ix::env::NameData::Str(parent, _, _) => parent.clone(),
      _ => continue,
    };
    let cases_on_name = Name::str(ind_name, "casesOn".to_string());
    // Only generate if the original env has this constant.
    if lean_env.get(&cases_on_name).is_some()
      && let Some(aux_def) =
        cases_on::generate_cases_on(&cases_on_name, rec_val, lean_env)
    {
      patches.insert(cases_on_name, PatchedConstant::CasesOn(aux_def));
    }
  }

  // Phase 1c: Generate .recOn definitions (arg-reordered .rec wrapper).
  //
  // Only generate for original recursors (first n_classes), not auxiliary rec_N.
  // This is intentional: Lean does NOT generate recOn_N for nested auxiliary
  // types (unlike below_N/brecOn_N which ARE generated via BRecOn.lean).
  for (rec_name, rec_val) in canonical_recs.iter().take(n_classes) {
    let ind_name = match rec_name.as_data() {
      crate::ix::env::NameData::Str(parent, _, _) => parent.clone(),
      _ => continue,
    };
    let rec_on_name = Name::str(ind_name, "recOn".to_string());
    if lean_env.get(&rec_on_name).is_some()
      && let Some(aux_def) = rec_on::generate_rec_on(&rec_on_name, rec_val)
    {
      patches.insert(rec_on_name, PatchedConstant::RecOn(aux_def));
    }
  }

  // Phase 2: Generate .below constants (if originals exist).
  let _p2_start = std::time::Instant::now();
  {
    let first_class_name = &sorted_classes[0][0];
    let below_name = Name::str(first_class_name.clone(), "below".to_string());
    // Guard: the existing constant must actually be a `.below` auxiliary,
    // not a coincidental name collision (e.g., a structure field accessor
    // like `IndPredBelow.NewDecl.below : NewDecl → LocalDecl`).
    // A genuine `.below` type always ends in `Sort _` after peeling foralls.
    if lean_env
      .get(&below_name)
      .is_some_and(|ci| is_below_shaped(ci.get_type()))
    {
      let _bt = std::time::Instant::now();
      let raw_below_consts = below::generate_below_constants(
        sorted_classes,
        &canonical_recs,
        lean_env,
        is_prop,
        stt,
        kctx,
      )?;
      let _below_elapsed = _bt.elapsed();

      // `below.rs` now derives `.below_N` names and internal cross-aux
      // references from already-source-indexed rec names (see
      // `below::generate_below_constants` → `aux_rec_suffix_idx`), so
      // there is no canonical-indexed leftover to rewrite. The
      // post-generation rename pass that used to live here is gone.
      let below_consts: Vec<below::BelowConstant> = raw_below_consts;

      for bc in &below_consts {
        match bc {
          below::BelowConstant::Def(d) => {
            patches
              .insert(d.name.clone(), PatchedConstant::BelowDef(d.clone()));
          },
          below::BelowConstant::Indc(i) => {
            patches
              .insert(i.name.clone(), PatchedConstant::BelowIndc(i.clone()));
          },
        }
      }

      // Populate canon_kenv with canonical .below types for Phase 3.
      // The canonical TC needs these to infer PProd(motive, I.below ...)
      // during brecOn generation. Uses the SAME renamed below_consts
      // that `patches` got — keeping the hash addressing consistent
      // end-to-end.
      populate_canon_kenv_with_below(
        &below_consts,
        sorted_classes,
        lean_env,
        stt,
        kctx,
      );

      // Phase 3: Generate .brecOn constants (if originals exist).
      let brecon_name =
        Name::str(first_class_name.clone(), "brecOn".to_string());
      if lean_env.get(&brecon_name).is_some() {
        let _brt = std::time::Instant::now();
        let brecon_consts = brecon::generate_brecon_constants(
          sorted_classes,
          &canonical_recs,
          &below_consts,
          lean_env,
          is_prop,
          stt,
          kctx,
        )?;
        let _brecon_elapsed = _brt.elapsed();
        for d in brecon_consts {
          // Only emit if the original Lean env has this constant
          // (e.g. .brecOn.eq may not be in the exported env subset).
          // `brecon.rs` now emits `.below_N` / sibling `.rec_N` references
          // in source-indexed form directly (the `below_consts` vec's
          // stored names are source-indexed by `below.rs` / aux_rec
          // naming, and intra-brecOn sibling refs use those names).
          // No post-generation rewrite is needed.
          if lean_env.get(&d.name).is_some() {
            patches.insert(d.name.clone(), PatchedConstant::BRecOn(d));
          }
        }

        let _gen_label = sorted_classes
          .first()
          .and_then(|c| c.first())
          .map(|n| n.pretty())
          .unwrap_or_default();
        if *crate::ix::compile::IX_TIMING
          && _below_elapsed.as_secs_f32() + _brecon_elapsed.as_secs_f32() > 0.3
        {
          eprintln!(
            "[gen_patches_detail] {:?} belowGen={:.2}s breconGen={:.2}s",
            _gen_label,
            _below_elapsed.as_secs_f32(),
            _brecon_elapsed.as_secs_f32(),
          );
        }
      }
    }
  }

  let _gen_label = sorted_classes
    .first()
    .and_then(|c| c.first())
    .map(|n| n.pretty())
    .unwrap_or_default();
  if *crate::ix::compile::IX_TIMING && _p1_elapsed.as_secs_f32() > 0.5 {
    eprintln!(
      "[gen_patches] {:?} recGen={:.2}s patches={}",
      _gen_label,
      _p1_elapsed.as_secs_f32(),
      patches.len(),
    );
  }

  // Note: `.noConfusion*`, `.ctorIdx`, `.ctorElim*`, `.ctor.inj*`, and
  // similar auxiliaries are intentionally NOT regenerated here. Their values
  // only invoke `.casesOn` (never `.rec` directly), and `.casesOn`'s public
  // binder arity is invariant under alpha collapse. Compiling the original
  // Lean definitions against our regenerated `.casesOn` produces correct
  // results — verified end-to-end by the validate-aux roundtrip test.
  // See the module-level documentation for the full classification.

  // Register patches for non-representative names (alpha-collapsed aliases).
  // Each alias gets deep-renamed: internal Const references to the
  // representative's auxiliaries are rewritten to reference the alias's own.
  let mut alias_patches: Vec<(Name, PatchedConstant)> = Vec::new();
  for class in sorted_classes {
    if class.len() <= 1 {
      continue;
    }
    let rep = &class[0];
    for alias in &class[1..] {
      // Build the rep→alias name map for deep renaming.
      let name_map = build_alias_name_map(rep, alias, lean_env);

      // For each active suffix that has a patch for rep, register the same for alias.
      let suffixes = ["rec", "recOn", "casesOn", "below", "brecOn"];
      for suffix in &suffixes {
        let rep_name = Name::str(rep.clone(), suffix.to_string());
        let alias_name = Name::str(alias.clone(), suffix.to_string());
        if let Some(patch) = patches.get(&rep_name) {
          if *suffix == "rec" {
            if lean_env.get(&alias_name).is_some() {
              aliases.insert(alias_name, rep_name);
            }
            continue;
          }

          // BelowIndc needs structural renaming (constructor names in the
          // BelowCtor structs change too, not just expression-level Consts).
          let aliased = match patch {
            PatchedConstant::BelowIndc(bi) => PatchedConstant::BelowIndc(
              below::rename_below_indc(bi, alias, rep, lean_env),
            ),
            _ => rename_patch(patch, &alias_name, &name_map),
          };
          alias_patches.push((alias_name, aliased));
        }
      }
      // Also .brecOn.go and .brecOn.eq — sub-names of brecOn that are
      // generated for Type-level inductives by build_type_brecon_fvar.
      for sub in &["go", "eq"] {
        let rep_base = Name::str(rep.clone(), "brecOn".to_string());
        let alias_base = Name::str(alias.clone(), "brecOn".to_string());
        let rep_name = Name::str(rep_base, sub.to_string());
        let alias_name = Name::str(alias_base, sub.to_string());
        if let Some(patch) = patches.get(&rep_name) {
          let aliased = rename_patch(patch, &alias_name, &name_map);
          alias_patches.push((alias_name, aliased));
        }
      }

      // Note: _N suffixed names (rec_1, below_1, brecOn_1, etc.) are NOT
      // aliased here. They always hang off all[0] (the first inductive in
      // source order), not per-class-representative. There is no TreeB.rec_1
      // in Lean — only TreeA.rec_1.
    }
  }
  for (name, patch) in alias_patches {
    patches.insert(name, patch);
  }

  // Register original-order auxiliary aliases. When alpha-collapse merges
  // inductives, the source Lean block may export more nested auxiliaries than
  // the canonical block. E.g. source has `rec_1` and `rec_2`, but after
  // collapse both source aux positions map to one canonical aux. Do not create
  // renamed synthetic patches for the extra source names; record address
  // aliases to the one generated canonical patch instead.
  if structural_has_nested
    && let Some(perm) = captured_perm.as_ref()
    && captured_n_canonical_aux > 0
    && let Some(first_orig_name) = original_all.first()
  {
    let mut source_of_canonical = vec![usize::MAX; captured_n_canonical_aux];
    for (source_j, &canonical_i) in perm.iter().enumerate() {
      if canonical_i != nested::PERM_OUT_OF_SCC
        && canonical_i < captured_n_canonical_aux
        && source_of_canonical[canonical_i] == usize::MAX
      {
        source_of_canonical[canonical_i] = source_j;
      }
    }

    let find_target =
      |canonical_i: usize, mk_name: &dyn Fn(usize) -> Name| -> Option<Name> {
        // Prefer the deterministic representative used by generation, but fall
        // back to any already-generated patch in the same equivalence class.
        if let Some(&source_j) = source_of_canonical.get(canonical_i)
          && source_j != usize::MAX
        {
          let target = mk_name(source_j);
          if patches.contains_key(&target) {
            return Some(target);
          }
        }
        for (source_j, &source_canonical_i) in perm.iter().enumerate() {
          if source_canonical_i == canonical_i {
            let target = mk_name(source_j);
            if patches.contains_key(&target) {
              return Some(target);
            }
          }
        }
        None
      };

    for (source_j, &canonical_i) in perm.iter().enumerate() {
      if canonical_i == nested::PERM_OUT_OF_SCC
        || canonical_i >= captured_n_canonical_aux
      {
        continue;
      }

      let source_idx = source_j + 1;
      for suffix in &["rec", "below", "brecOn"] {
        let mk_name = |j: usize| {
          Name::str(first_orig_name.clone(), format!("{suffix}_{}", j + 1))
        };
        let source_name =
          Name::str(first_orig_name.clone(), format!("{suffix}_{source_idx}"));
        if patches.contains_key(&source_name)
          || lean_env.get(&source_name).is_none()
        {
          continue;
        }
        let Some(target_name) = find_target(canonical_i, &mk_name) else {
          return Err(CompileError::InvalidMutualBlock {
            reason: format!(
              "aux_gen alias target missing: {} maps to canonical aux #{} but no generated {suffix} patch exists",
              source_name.pretty(),
              canonical_i,
            ),
          });
        };
        if target_name != source_name {
          aliases.insert(source_name, target_name);
        }
      }

      for sub in &["go", "eq"] {
        let mk_name = |j: usize| {
          let base =
            Name::str(first_orig_name.clone(), format!("brecOn_{}", j + 1));
          Name::str(base, sub.to_string())
        };
        let source_base =
          Name::str(first_orig_name.clone(), format!("brecOn_{source_idx}"));
        let source_name = Name::str(source_base, sub.to_string());
        if patches.contains_key(&source_name)
          || lean_env.get(&source_name).is_none()
        {
          continue;
        }
        let Some(target_name) = find_target(canonical_i, &mk_name) else {
          return Err(CompileError::InvalidMutualBlock {
            reason: format!(
              "aux_gen alias target missing: {} maps to canonical aux #{} but no generated brecOn.{sub} patch exists",
              source_name.pretty(),
              canonical_i,
            ),
          });
        };
        if target_name != source_name {
          aliases.insert(source_name, target_name);
        }
      }
    }
  }

  Ok(AuxPatchesOutput {
    patches,
    aliases,
    perm: captured_perm,
    n_classes,
    n_canonical_aux: captured_n_canonical_aux,
    n_source_aux: captured_n_source_aux,
  })
}

/// Check whether a type expression is shaped like a `.below` auxiliary.
///
/// A genuine `.below` type is a forall telescope ending in `Sort _`:
///   `∀ {params} {motives} (indices) (major), Sort rlvl`
///
/// This distinguishes `.below` auxiliaries from coincidental name collisions
/// like structure field accessors (e.g., `NewDecl.below : NewDecl → LocalDecl`).
fn is_below_shaped(typ: &LeanExpr) -> bool {
  use crate::ix::env::ExprData;
  let mut cur = typ;
  loop {
    match cur.as_data() {
      ExprData::ForallE(_, _, body, _, _) => cur = body,
      ExprData::Sort(_, _) => return true,
      _ => return false,
    }
  }
}

/// Extract the parent prefix from a Name.
/// E.g., `A.rec` → `A`, `A.below` → `A`.
fn _name_parent(name: &Name) -> Name {
  match name.as_data() {
    crate::ix::env::NameData::Str(parent, _, _)
    | crate::ix::env::NameData::Num(parent, _, _) => parent.clone(),
    crate::ix::env::NameData::Anonymous(_) => Name::anon(),
  }
}

/// Build a name substitution map for aliasing `rep` → `alias`.
///
/// Covers the inductive itself, its constructors (positional mapping),
/// and all known auxiliary suffixes. This ensures `replace_const_names`
/// rewrites all internal Const references when creating alias patches.
fn build_alias_name_map(
  rep: &Name,
  alias: &Name,
  lean_env: &Arc<LeanEnv>,
) -> std::collections::HashMap<Name, Name> {
  let mut map = std::collections::HashMap::new();

  // Inductive name itself.
  map.insert(rep.clone(), alias.clone());

  // Constructor names: positional mapping rep.ctor_i → alias.ctor_i.
  let rep_ctors = match lean_env.get(rep) {
    Some(crate::ix::env::ConstantInfo::InductInfo(v)) => v.ctors.clone(),
    _ => vec![],
  };
  let alias_ctors = match lean_env.get(alias) {
    Some(crate::ix::env::ConstantInfo::InductInfo(v)) => v.ctors.clone(),
    _ => vec![],
  };
  for (rc, ac) in rep_ctors.iter().zip(alias_ctors.iter()) {
    map.insert(rc.clone(), ac.clone());
  }

  // Auxiliary suffixes that can appear as Const references inside patch
  // expressions. We only list the ones we actually regenerate — auxiliaries
  // we don't regenerate (`.noConfusion*`, `.ctorIdx`, etc.) are never
  // emitted by this pipeline, so no rename entries are needed for them.
  for suffix in &["rec", "recOn", "casesOn", "below", "brecOn"] {
    map.insert(
      Name::str(rep.clone(), suffix.to_string()),
      Name::str(alias.clone(), suffix.to_string()),
    );
  }

  // Sub-names of brecOn.
  for sub in &["go", "eq"] {
    let rep_sub =
      Name::str(Name::str(rep.clone(), "brecOn".to_string()), sub.to_string());
    let alias_sub = Name::str(
      Name::str(alias.clone(), "brecOn".to_string()),
      sub.to_string(),
    );
    map.insert(rep_sub, alias_sub);
  }

  // Below constructor names (for Prop-level .below inductives).
  let rep_below = Name::str(rep.clone(), "below".to_string());
  let alias_below = Name::str(alias.clone(), "below".to_string());
  map.insert(rep_below.clone(), alias_below.clone());
  // Map positional .below constructors: Rep.below.ctor_suffix → Alias.below.ctor_suffix.
  for (rc, ac) in rep_ctors.iter().zip(alias_ctors.iter()) {
    if let Some(rc_suffix) = rc.strip_prefix(rep) {
      let rep_bc = rep_below.append_components(&rc_suffix);
      let alias_bc = alias_below.append_components(
        &ac.strip_prefix(alias).unwrap_or_else(|| ac.components()),
      );
      map.insert(rep_bc, alias_bc);
    }
  }

  map
}

/// Clone a PatchedConstant with a new name, rewriting internal Const
/// references via `name_map`.
fn rename_patch(
  patch: &PatchedConstant,
  new_name: &Name,
  name_map: &std::collections::HashMap<Name, Name>,
) -> PatchedConstant {
  match patch {
    PatchedConstant::Rec(r) => {
      let mut r2 = r.clone();
      r2.cnst.name = new_name.clone();
      PatchedConstant::Rec(r2)
    },
    PatchedConstant::RecOn(d) => PatchedConstant::RecOn(AuxDef {
      name: new_name.clone(),
      level_params: d.level_params.clone(),
      typ: expr_utils::replace_const_names(&d.typ, name_map),
      value: expr_utils::replace_const_names(&d.value, name_map),
      is_unsafe: d.is_unsafe,
    }),
    PatchedConstant::CasesOn(d) => PatchedConstant::CasesOn(AuxDef {
      name: new_name.clone(),
      level_params: d.level_params.clone(),
      typ: expr_utils::replace_const_names(&d.typ, name_map),
      value: expr_utils::replace_const_names(&d.value, name_map),
      is_unsafe: d.is_unsafe,
    }),
    PatchedConstant::BelowDef(d) => {
      PatchedConstant::BelowDef(below::BelowDef {
        name: new_name.clone(),
        level_params: d.level_params.clone(),
        typ: expr_utils::replace_const_names(&d.typ, name_map),
        value: expr_utils::replace_const_names(&d.value, name_map),
        is_unsafe: d.is_unsafe,
      })
    },
    PatchedConstant::BelowIndc(i) => {
      // BelowIndc is handled by rename_below_indc at the call site.
      // This arm is a fallback — just rename the name.
      PatchedConstant::BelowIndc(below::BelowIndc {
        name: new_name.clone(),
        ..i.clone()
      })
    },
    PatchedConstant::BRecOn(d) => PatchedConstant::BRecOn(brecon::BRecOnDef {
      name: new_name.clone(),
      level_params: d.level_params.clone(),
      typ: expr_utils::replace_const_names(&d.typ, name_map),
      value: expr_utils::replace_const_names(&d.value, name_map),
      is_unsafe: d.is_unsafe,
      is_prop: d.is_prop,
    }),
  }
}

/// Populate `stt.canon_kenv` with canonical `.below` types and their
/// dependencies (parent inductives, constructors, PUnit, PProd).
///
/// The canonical `.below` types match the alpha-collapsed block structure
/// and may differ from the originals in `lean_env`. The canonical TC
/// (`stt.canon_tc`) uses `canon_kenv` exclusively, so it sees the
/// correct types for PProd(motive, I.below ...) inference.
pub(crate) fn populate_canon_kenv_with_below(
  below_consts: &[below::BelowConstant],
  sorted_classes: &[Vec<Name>],
  lean_env: &crate::ix::env::Env,
  stt: &CompileState,
  kctx: &crate::ix::compile::KernelCtx,
) {
  use crate::ix::kernel::constant::KConst;
  use crate::ix::kernel::id::KId;
  use crate::ix::kernel::ingress::{
    lean_expr_to_zexpr_with_kenv, resolve_lean_name_addr,
  };

  let n2a = Some(&stt.name_to_addr);
  let aux_n2a = Some(&stt.aux_name_to_addr);
  let canon = &kctx.kenv;

  // Ensure PUnit and PProd are in kenv.
  expr_utils::ensure_prelude_in_kenv_of(stt, kctx);

  // Ensure parent inductives (and their constructors) are in canon_kenv.
  // The .below types reference these in their motive/major domains.
  for class in sorted_classes {
    let rep = &class[0];
    expr_utils::ensure_in_kenv_of(rep, lean_env, stt, kctx);
  }

  // Insert canonical .below definitions/inductives.
  for bc in below_consts {
    match bc {
      below::BelowConstant::Def(d) => {
        let addr = resolve_lean_name_addr(&d.name, n2a, aux_n2a);
        let zid = KId::new(addr, d.name.clone());
        let ty_z = lean_expr_to_zexpr_with_kenv(
          &d.typ,
          &d.level_params,
          &kctx.kenv,
          n2a,
          aux_n2a,
        );
        let val_z = lean_expr_to_zexpr_with_kenv(
          &d.value,
          &d.level_params,
          &kctx.kenv,
          n2a,
          aux_n2a,
        );
        canon.insert(
          zid.clone(),
          KConst::Defn {
            name: d.name.clone(),
            level_params: d.level_params.clone(),
            kind: crate::ix::ixon::constant::DefKind::Definition,
            safety: crate::ix::env::DefinitionSafety::Safe,
            hints: crate::ix::env::ReducibilityHints::Abbrev,
            lvls: d.level_params.len() as u64,
            ty: ty_z,
            val: val_z,
            lean_all: vec![],
            block: zid,
          },
        );
      },
      below::BelowConstant::Indc(i) => {
        let addr = resolve_lean_name_addr(&i.name, n2a, aux_n2a);
        let zid = KId::new(addr, i.name.clone());
        let ty_z = lean_expr_to_zexpr_with_kenv(
          &i.typ,
          &i.level_params,
          &kctx.kenv,
          n2a,
          aux_n2a,
        );
        let mut ctor_zids = Vec::new();
        for ctor in &i.ctors {
          let ctor_addr = resolve_lean_name_addr(&ctor.name, n2a, aux_n2a);
          let ctor_zid = KId::new(ctor_addr, ctor.name.clone());
          let ctor_ty_z = lean_expr_to_zexpr_with_kenv(
            &ctor.typ,
            &i.level_params,
            &kctx.kenv,
            n2a,
            aux_n2a,
          );
          canon.insert(
            ctor_zid.clone(),
            KConst::Ctor {
              name: ctor.name.clone(),
              level_params: i.level_params.clone(),
              is_unsafe: false,
              lvls: i.level_params.len() as u64,
              induct: zid.clone(),
              cidx: ctor_zids.len() as u64,
              params: ctor.n_params as u64,
              fields: ctor.n_fields as u64,
              ty: ctor_ty_z,
            },
          );
          ctor_zids.push(ctor_zid);
        }
        canon.insert(
          zid.clone(),
          KConst::Indc {
            name: i.name.clone(),
            level_params: i.level_params.clone(),
            lvls: i.level_params.len() as u64,
            params: i.n_params as u64,
            indices: i.n_indices as u64,
            is_rec: false,
            is_refl: false,
            is_unsafe: false,
            ctors: ctor_zids,
            ty: ty_z,
            block: zid,
            nested: 0,
            member_idx: 0,
            lean_all: vec![],
          },
        );
      },
    }
  }
}
